async (params, browser) => {
  // Search flights on Expedia
  await browser.open(`https://www.expedia.com/Flights-Search?leg1=from:${params.origin},to:${params.destination},departure:${params.departure_date}TANYT&passengers=adults:1&trip=oneway&mode=search`)

  // Wait for flight results
  await browser.waitForSelector('[data-stid=\'section-results\'] li, ul[data-stid=\'results-list\'] li, [data-test-id=\'offer-listing\']', 25000)

  // Let results render
  await browser.wait(4000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract flight results
  const flight_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-test-id="offer-listing"], ul[data-stid="results-list"] > li, [data-stid="section-results"] li'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const allText = el.textContent || ''; const spans = el.querySelectorAll('span'); const divs = el.querySelectorAll('div'); let airline = ''; let departTime = ''; let arriveTime = ''; let duration = ''; let stops = ''; let price = ''; for (let s = 0; s < spans.length; s++) { const t = spans[s].textContent.trim(); if (t.match(/^\d{1,2}:\d{2}\s*(AM|PM|am|pm)$/)) { if (!departTime) departTime = t; else if (!arriveTime) arriveTime = t; } if (t.match(/^\d+h\s*\d*m?$/) || t.match(/^\d+\s*hr/)) duration = t; if (t.match(/nonstop|Nonstop|\d+\s*stop/i)) stops = t; if (t.match(/^\$[\d,.]+$/)) price = t; } for (let d = 0; d < divs.length; d++) { const t = divs[d].textContent.trim(); if (!airline && t.match(/Airlines?|Airways?|Air\s|United|Delta|American|Southwest|JetBlue|Spirit|Frontier|Alaska|Hawaiian/i) && t.length < 40) airline = t; } const linkEl = el.querySelector('a[href], button[data-test-id="select-button"]'); const logoEl = el.querySelector('img[alt]'); if (!airline && logoEl) airline = logoEl.getAttribute('alt') || ''; results.push({ airline: airline, departure_time: departTime, arrival_time: arriveTime, duration: duration, stops: stops, price: price, url: linkEl && linkEl.href ? linkEl.href : window.location.href }); } return { origin: params.origin, destination: params.destination, departure_date: params.departure_date, result_count: results.length, results: results }`)

  return flight_results
}
